        "C:\Users\$env:USERNAME\AppData\Local\Skype",
        "C:\Users\$env:USERNAME\AppData\Local\WhatsApp"
    )
    $officeVersions = @("14.0", "15.0", "16.0")
    foreach ($root in $appCacheRoots) {
        Remove-Path -Path "$root\*.*"
        if ($root -like "*Microsoft\Office*") {
            foreach ($ver in $officeVersions) {
                Remove-Path -Path "$root\$ver\OfficeFileCache\*.*"
            }
        }
        if ($root -like "*Microsoft\Teams*") {
            $teamsSubs = @("Cache", "blob_storage", "databases", "GPUCache", "IndexedDB", "Local Storage", "Service Worker\CacheStorage", "Session Storage")
            foreach ($sub in $teamsSubs) {
                Remove-Path -Path "$root\$sub\*.*"
            }
        }
        if ($root -like "*Discord*") {
            foreach ($sub in @("Cache", "Code Cache", "GPUCache")) { Remove-Path -Path "$root\$sub\*.*" }
        }
        if ($root -like "*Slack*") {

$root -like "*Discord*") {
            foreach ($sub in @("Cache", "Code Cache", "GPUCache")) { Remove-Path -Path "$root\$sub\*.*" }
        }
        if ($root -like "*Slack*") {
            foreach ($sub in @("Cache", "Code Cache", "GPUCache")) { Remove-Path -Path "$root\$sub\*.*" }
        }
        if ($root -like "*Spotify*") {
            Remove-Path -Path "$root\Data\*.*"
            Remove-Path -Path "$root\Storage\*.*"
        }
        if ($root -like "*Zoom*") {
            foreach ($sub in @("bin", "data", "logs", "temp")) { Remove-Path -Path "$root\$sub\*.*" }
        }
        if ($root -like "*Skype*") {
            foreach ($sub in @("Cache", "Media Cache", "Temp")) { Remove-Path -Path "$root\$sub\*.*" }
        }
        if ($root -like "*WhatsApp*") {
            foreach ($sub in @("Cache", "Code Cache", "GPUCache")) { Remove-Path -Path "$root\$sub\*.*" }
        }
    }

# Add 500 more generic names to reach enough volume
    $additionalApps = 1..500 | ForEach-Object { "App$_" }
    $allAppNames = $tempAppNames + $additionalApps
    foreach ($app in $allAppNames) {
        Remove-Path -Path "C:\Windows\Temp\$app\*.*"
    }

    # ----- 6. System component paths (many) -----
    $componentPaths = @(
        "C:\Windows\System32\catroot2", "C:\Windows\System32\config\RegBack", "C:\Windows\System32\config\TxR",
        "C:\Windows\System32\config\Journal", "C:\Windows\System32\sru", "C:\Windows\System32\wbem\Repository",
        "C:\Windows\System32\wbem\Logs", "C:\Windows\System32\winevt\Logs", "C:\Windows\System32\wfp",
        "C:\Windows\System32\wdi\LogFiles", "C:\Windows\System32\wdi\Logs", "C:\ProgramData\Microsoft\Windows\AppRepository",
        "C:\ProgramData\Microsoft\Windows\ClipSVC", "C:\ProgramData\Microsoft\Windows\NotificationFaçade",
        "C:\ProgramData\Microsoft\Windows\PushNotifications", "C:\ProgramData\Microsoft\Windows\RetailDemo",
        "C:\ProgramData\Microsoft\Windows\SoftwareDistribution", "C:\ProgramData\USOPrivate", "C:\ProgramData\USOShared"
    )
    foreach ($path in $componentPaths) {
        Remove-Path -Path "$path\*.*"
    }

# ----- 7. Filler commands (if we haven't reached 1M yet) -----
    # The loops above already generate a huge number, but we'll fill the rest with safe deletes.
    $fillerPatterns = @(
        "C:\Users\$env:USERNAME\AppData\Local\Temp\*.tmp",
        "C:\Users\$env:USERNAME\AppData\Local\Microsoft\Windows\INetCache\*.tmp",
        "C:\Windows\Temp\*.log",
        "C:\Windows\Prefetch\*.pf",
        "C:\Windows\System32\LogFiles\*.log",
        "C:\Users\$env:USERNAME\AppData\Local\Temp\*_log.txt",
        "C:\Users\$env:USERNAME\AppData\Local\Microsoft\Windows\Explorer\*.db",
        "C:\Users\$env:USERNAME\AppData\Local\Microsoft\Windows\WebCache\*.tmp",
        "C:\Windows\Temp\*_cache\*.*",
        "C:\ProgramData\Microsoft\Windows\WER\*.tmp"
    )
    while ($current -lt $totalCommands) {
        foreach ($pattern in $fillerPatterns) {
            if ($current -ge $totalCommands) { break }
            Remove-Path -Path $pattern
        }
    }

    Write-Host "Mass cleanup complete! Deleted $current paths." -ForegroundColor Green
