def generate_query(cls_name, props, filters):
    """Generate a WQL query string."""
    if props == "*":
        select = "*"
    else:
        select = ", ".join(props)
    where = ""
    if filters:
        prop, op, val = filters
        where = f" WHERE {prop} {op} {val}"
    return f"SELECT {select} FROM {cls_name}{where}"

